const config=require("./config");function generatePossibleSlugs(collectionName){if(!collectionName||"Unknown"===collectionName)return[];const slugs=[];let cleanName=collectionName.replace(/[^\w\s-]/g,"").trim();console.log(`🔍 Clean name: "${cleanName}"`);const slug1=cleanName.toLowerCase().replace(/\s+/g,"-").replace(/-+/g,"-").replace(/^-|-$/g,"");slug1&&(slugs.push(slug1),console.log(`📝 Strategy 1 (lowercase with hyphens): "${slug1}"`));const slug2=cleanName.toLowerCase().replace(/\s+/g,"").replace(/-+/g,"");slug2&&slug2!==slug1&&(slugs.push(slug2),console.log(`📝 Strategy 2 (lowercase no spaces): "${slug2}"`));const slug3=cleanName.toLowerCase().replace(/\s+/g,"_").replace(/-+/g,"_").replace(/_+/g,"_").replace(/^_|_$/g,"");slug3&&slug3!==slug1&&slug3!==slug2&&(slugs.push(slug3),console.log(`📝 Strategy 3 (lowercase with underscores): "${slug3}"`));const slug4=cleanName.replace(/\s+/g,"-").replace(/-+/g,"-").replace(/^-|-$/g,"");slug4&&slug4!==slug1&&slug4!==slug2&&slug4!==slug3&&(slugs.push(slug4),console.log(`📝 Strategy 4 (original case with hyphens): "${slug4}"`));const commonVariations=["dx-terminal","dxterminal","dx_terminal","dx-terminal-nft","dxterminal-nft","dx-terminal-game","dxterminal-game","dx-terminal-collection","dxterminal-collection"];for(const variation of commonVariations)slugs.includes(variation)||(slugs.push(variation),console.log(`📝 Strategy 5 (common variation): "${variation}"`));return[...new Set(slugs)]}async function testSlugsOnOpenSea(slugs,contractAddress=null){const apiKey=config.opensea.apiKey;if(console.log(`\n🔍 Testing ${slugs.length} slugs on OpenSea API v2...`),console.log("📍 Chain: base"),console.log("🔑 API Key: "+(apiKey?"✅ Set":"❌ Missing")),apiKey){for(const slug of slugs)try{console.log(`\n🔍 Testing slug: "${slug}"`);const response=await fetch(`https://api.opensea.io/api/v2/collections/${slug}?chain=base`,{headers:{"X-API-KEY":apiKey,Accept:"application/json"}});if(console.log(`📊 Response status: ${response.status} ${response.statusText}`),response.ok){const data=await response.json();if(console.log(`✅ Found collection: "${data.name||slug}"`),console.log(`🔗 Twitter: ${data.twitter_username||"N/A"}`),console.log(`📱 Discord: ${data.discord_url||"N/A"}`),console.log(`🌐 Website: ${data.project_url||"N/A"}`),console.log("📄 Description: "+(data.description?data.description.substring(0,100)+"...":"N/A")),contractAddress&&data.contracts){if(data.contracts.some((contract=>contract.address.toLowerCase()===contractAddress.toLowerCase())))return console.log("🎯 ✅ CONTRACT MATCH! This is the right collection!"),console.log("📋 Full collection data:",JSON.stringify(data,null,2)),data;console.log("⚠️ Contract mismatch - this is a different collection"),data.contracts.length>0&&console.log(`📋 Available contracts: ${data.contracts.map((c=>c.address)).join(", ")}`)}else console.log("📋 Full collection data:",JSON.stringify(data,null,2))}else if(404===response.status)console.log("❌ Collection not found (404)");else{console.log(`❌ API error: ${response.status} ${response.statusText}`);const errorText=await response.text();console.log(`📄 Error details: ${errorText}`)}}catch(error){console.log(`❌ Error testing slug "${slug}": ${error.message}`)}return console.log("\n❌ No matching collection found for any slug"),null}console.log("❌ OpenSea API key is missing in config.js")}async function testDXTerminalSlugs(){console.log("🚀 Testing DX Terminal collection slugs...\n");const possibleNames=["DX Terminal","DXTerminal","DX-Terminal","DX Terminal NFT","DXTerminal NFT","DX Terminal Game","DXTerminal Game"];for(const name of possibleNames){console.log(`\n🔍 Testing name: "${name}"`),console.log("─".repeat(50));const slugs=generatePossibleSlugs(name);console.log(`\n📋 Generated ${slugs.length} slugs: ${slugs.join(", ")}`);const result=await testSlugsOnOpenSea(slugs,"0x41dc69132cce31fcbf6755c84538ca268520246f");if(result)return console.log(`\n🎉 SUCCESS! Found DX Terminal collection with slug: "${result.slug||"unknown"}"`),result}console.log("\n❌ No DX Terminal collection found with any name variation")}testDXTerminalSlugs().catch(console.error);